use cor24_emulator::EmulatorCore;

#[test]
fn test_hello_world_loads_and_runs() {
    let pvm_binary = web_dv24r::config::PVM_BINARY;
    let hello_p24 = include_bytes!(concat!(env!("OUT_DIR"), "/hello.p24"));
    let image = pa24r::load_p24(hello_p24).unwrap();

    let mut emu = EmulatorCore::new();
    emu.hard_reset();
    emu.set_uart_tx_busy_cycles(0);
    emu.load_program(0, pvm_binary);
    emu.load_program_extent(pvm_binary.len() as u32);

    // Load demo at safe address with data relocation
    let load_addr: u32 = 0x010000;
    let code_size = image.code.len() as u32;
    let total = code_size + image.data.len() as u32;

    // Write code + data contiguously
    for (i, &b) in image.code.iter().chain(image.data.iter()).enumerate() {
        emu.write_byte(load_addr + i as u32, b);
    }

    // Relocate push instructions with data references
    let mut i: u32 = 0;
    while i < code_size {
        let op = emu.read_byte(load_addr + i);
        let size = match op {
            0x01 | 0x30..=0x33 | 0x54..=0x56 => 4, // IMM24
            0x02 | 0x34..=0x36 | 0x40 | 0x42..=0x45 | 0x57 | 0x60 => 2, // IMM8
            0x58 | 0x59 => 3,                      // D8_O8
            0x5A => 5,                             // D8_A24
            _ => 1,                                // NONE
        };
        if op == 0x01 && i + 4 <= code_size {
            let lo = emu.read_byte(load_addr + i + 1) as u32;
            let mid = emu.read_byte(load_addr + i + 2) as u32;
            let hi = emu.read_byte(load_addr + i + 3) as u32;
            let val = lo | (mid << 8) | (hi << 16);
            if val >= code_size && val < total {
                let abs = val + load_addr;
                emu.write_byte(load_addr + i + 1, abs as u8);
                emu.write_byte(load_addr + i + 2, (abs >> 8) as u8);
                emu.write_byte(load_addr + i + 3, (abs >> 16) as u8);
            }
        }
        i += size;
    }

    // Put halt at code_seg so pvm.s init halts cleanly
    let code_seg = web_dv24r::config::label_addr("code_seg");
    emu.write_byte(code_seg, 0x60); // sys
    emu.write_byte(code_seg + 1, 0x00); // halt

    // Run pvm.s init
    emu.set_pc(0);
    emu.resume();
    emu.run_batch(10_000);

    // Soft reset (clears halted, preserves memory)
    emu.reset();
    emu.set_uart_tx_busy_cycles(0);
    emu.clear_uart_output();

    // Set up for demo execution
    let vm_state = web_dv24r::config::label_addr("vm_state");
    let vm_loop = web_dv24r::config::label_addr("vm_loop");
    emu.set_pc(vm_loop);
    emu.set_reg(3, vm_state); // fp = &vm_state

    // Patch vm_state
    // code = load_addr
    emu.write_byte(vm_state + 18, load_addr as u8);
    emu.write_byte(vm_state + 19, (load_addr >> 8) as u8);
    emu.write_byte(vm_state + 20, (load_addr >> 16) as u8);
    // pc = 0
    emu.write_byte(vm_state, 0);
    emu.write_byte(vm_state + 1, 0);
    emu.write_byte(vm_state + 2, 0);
    // status = 0
    emu.write_byte(vm_state + 21, 0);
    emu.write_byte(vm_state + 22, 0);
    emu.write_byte(vm_state + 23, 0);

    // Run
    emu.resume();
    let result = emu.run_batch(500_000);
    let output = emu.get_uart_output();
    println!(
        "demo: {} instrs, {:?}",
        result.instructions_run, result.reason
    );
    println!("output: {output:?}");

    assert!(result.instructions_run > 0);
    assert!(output.contains("Hello"), "got: {output:?}");
}

use cor24_emulator::EmulatorCore;

/// Tiny program: print "1", call a proc that prints "2", then print "3"
/// If we see "123" the call/ret works. If "1" only, call breaks.
/// If "12" only, ret breaks.
const TINY_CALL: &str = "\
.proc main 0
    push_s 49
    sys 1
    call foo
    push_s 51
    sys 1
    halt
.end

.proc foo 0
    push_s 50
    sys 1
    ret 0
.end
";

fn run_fast(source: &str) -> String {
    let pvm = web_dv24r::config::PVM_BINARY;
    let vm_state = web_dv24r::config::label_addr("vm_state");
    let code_seg = web_dv24r::config::label_addr("code_seg");
    let vm_loop = web_dv24r::config::label_addr("vm_loop");

    let result = pa24r::assemble(source);
    assert!(result.errors.is_empty(), "errors: {:?}", result.errors);

    let load_addr: u32 = 0x010000;
    let mut code = result.code.clone();
    let code_size = code.len() as u32;
    let data_size = result.data.len() as u32;
    pa24r::relocate_data_refs(&mut code, code_size, data_size, load_addr);

    let mut emu = EmulatorCore::new();
    emu.hard_reset();
    emu.set_uart_tx_busy_cycles(0);
    emu.load_program(0, pvm);
    emu.load_program_extent(pvm.len() as u32);

    // Write demo
    for (i, &b) in code.iter().chain(result.data.iter()).enumerate() {
        emu.write_byte(load_addr + i as u32, b);
    }

    // Halt at code_seg
    emu.write_byte(code_seg, 0x60);
    emu.write_byte(code_seg + 1, 0x00);

    // Boot pvm.s
    emu.set_pc(0);
    emu.resume();
    emu.run_batch(10_000);

    // Reset, set up for demo
    emu.reset();
    emu.set_uart_tx_busy_cycles(0);
    emu.clear_uart_output();
    emu.set_pc(vm_loop);
    emu.set_reg(3, vm_state);

    // Patch vm_state
    emu.write_byte(vm_state + 18, load_addr as u8);
    emu.write_byte(vm_state + 19, (load_addr >> 8) as u8);
    emu.write_byte(vm_state + 20, (load_addr >> 16) as u8);
    emu.write_byte(vm_state, 0);
    emu.write_byte(vm_state + 1, 0);
    emu.write_byte(vm_state + 2, 0);
    emu.write_byte(vm_state + 21, 0);
    emu.write_byte(vm_state + 22, 0);
    emu.write_byte(vm_state + 23, 0);

    emu.resume();
    emu.run_batch(500_000);
    emu.get_uart_output().to_string()
}

#[test]
fn test_no_call() {
    // Simplest possible: just print "A"
    let output = run_fast(".proc main 0\n    push_s 65\n    sys 1\n    halt\n.end\n");
    println!("no_call output: {:?}", output);
    assert!(output.contains("A"), "got: {:?}", output);
}

#[test]
fn test_call_and_ret() {
    let output = run_fast(TINY_CALL);
    println!("call_ret output: {:?}", output);
    assert!(output.starts_with("123"), "got: {:?}", output);
}

#[test]
fn test_call_with_arg() {
    // Pass argument 42, callee prints it as '*'
    let output = run_fast(
        "\
.proc main 0
    push_s 49
    sys 1
    push_s 42
    call star
    push_s 51
    sys 1
    halt
.end

.proc star 1
    loada 0
    sys 1
    ret 1
.end
",
    );
    println!("call_with_arg output: {:?}", output);

    // Detailed trace of the call_with_arg program
    let result2 = pa24r::assemble(
        "\
.proc main 0
    push_s 49
    sys 1
    push_s 42
    call star
    push_s 51
    sys 1
    halt
.end

.proc star 1
    loada 0
    sys 1
    ret 1
.end
",
    );
    print!("code: ");
    for b in &result2.code {
        print!("{:02X} ", b);
    }
    println!();

    // Disassemble
    let ops: Vec<(&str, usize)> = vec![
        ("enter", 2),
        ("push_s", 2),
        ("sys", 2),
        ("push_s", 2),
        ("call", 4),
        ("push_s", 2),
        ("sys", 2),
        ("halt", 1),
        ("leave", 1),
        ("enter", 2),
        ("loada", 2),
        ("sys", 2),
        ("ret", 2),
        ("leave", 1),
    ];
    let mut off = 0;
    for (name, size) in &ops {
        if off + size <= result2.code.len() {
            if *size == 4 {
                let val = result2.code[off + 1] as u32
                    | (result2.code[off + 2] as u32) << 8
                    | (result2.code[off + 3] as u32) << 16;
                println!("  {:04X}: {} 0x{:06X}", off, name, val);
            } else if *size == 2 {
                println!("  {:04X}: {} {}", off, name, result2.code[off + 1]);
            } else {
                println!("  {:04X}: {}", off, name);
            }
        }
        off += size;
    }

    assert!(output.starts_with("1*3"), "got: {:?}", output);
}
